-- H2O Benchmark: Temporal Count Queries for Elasticsearch SQL
-- 264 x 10-minute (600s) non-overlapping windows from 2024-01-01T00:00:00Z

-- C000: count window ending at 2024-01-01T00:10:00Z
SELECT COUNT(*) AS row_count FROM h2o_benchmark WHERE timestamp BETWEEN DATEADD('second', -600, CAST('2024-01-01T00:10:00Z' AS DATETIME)) AND CAST('2024-01-01T00:10:00Z' AS DATETIME);
